#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>

#define TILE_SIZE 32

template<typename T>
__device__ T zero_value();

template<>
__device__ float zero_value<float>() {
    return 0.0f;
}

template<>
__device__ __half zero_value<__half>() {
    return __float2half(0.0f);
}

template<typename T>
__device__ T add(T a, T b);

template<>
__device__ float add<float>(float a, float b) {
    return a + b;
}

template<>
__device__ __half add<__half>(__half a, __half b) {
    return __hadd(a, b);
}

template<typename T>
__device__ T mul(T a, T b);

template<>
__device__ float mul<float>(float a, float b) {
    return a * b;
}

template<>
__device__ __half mul<__half>(__half a, __half b) {
    return __hmul(a, b);
}

template<typename T>
__device__ T scalar_mul(T a, float b);

template<>
__device__ float scalar_mul<float>(float a, float b) {
    return a * b;
}

template<>
__device__ __half scalar_mul<__half>(__half a, float b) {
    return __hmul(a, __float2half(b));
