template<typename T>
__global__ void fused_matmul_residual_kernel(
    const T* __restrict__ input,
    const T* __restrict__ weight,
    const T* __restrict__ bias,
    T* __restrict__ output,
    float scaling_factor,
    int batch_size,
    int in_features,
    int out_features
) {
    // Shared memory for tiling
    __shared__ T As[TILE_SIZE][TILE_SIZE];
    __shared__ T Bs[TILE_SIZE][TILE_SIZE];

    int row = blockIdx.y / TILE_SIZE + threadIdx.y;
    int col = blockIdx.x * TILE_SIZE + threadIdx.x;

    T sum = zero_value<T>();

    // Loop over tiles
    for (int t = 0; t < (in_features + TILE_SIZE - 1) / TILE_SIZE; ++t) {
        // Load tile from input matrix (A)
        int a_row = row;
        int a_col = t * TILE_SIZE + threadIdx.x;
        if (a_row < batch_size && a_col < in_features) {
            As[threadIdx.y][threadIdx.x] = input[a_row * in_features + a_col];
        } else {
            As[threadIdx.y][threadIdx.x] = zero_value<T>();
        }

        // Load tile from weight matrix (B) - note: weight is [out_features, in_features]
        int b_row = t * TILE_SIZE + threadIdx.y;
        int b_col = col;
        if (b_row < in_features && b_col < out_features) {
            Bs[threadIdx.y][threadIdx.x] = weight[b_col * in_features + b_row];  // Transposed access
        } else {
            Bs[threadIdx.y][threadIdx.x] = zero_value<T>();
