#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>

#define TILE_SIZE 32

template<typename T>
__device__ T zero_value();

template<>
__device__ float zero_value<float>() {
    return 0.0f;
}

template<>
__device__ __half zero_value<__half>() {
    return __float2half(0.0f);
}

template<typename T>
__device__ T add(T a, T b);

template<>
__device__ float add<float>(float a, float b) {
    return a + b;
}

template<>
__device__ __half add<__half>(__half a, __half b) {
    return __hadd(a, b);
}

template<typename T>
__device__ T mul(T a, T b);

template<>
__device__ float mul<float>(float a, float b) {
    return a * b;
}

template<>
__device__ __half mul<__half>(__half a, __half b) {
    return __hmul(a, b);
}

template<typename T>
__device__ T scalar_mul(T a, float b);

template<>
__device__ float scalar_mul<float>(float a, float b) {
    return a * b;
}

template<>
__device__ __half scalar_mul<__half>(__half a, float b) {
    return __hmul(a, __float2half(b));
}

template<typename T>
__global__ void fused_matmul_residual_kernel(
    const T* __restrict__ input,
    const T* __restrict__ weight,
    const T* __restrict__ bias,
    T* __restrict__ output,
    float scaling_factor,
    int batch_size,
    int in_features,
    int out_features
) {
    // Shared memory for tiling
    __shared__ T As[TILE_SIZE][TILE_SIZE];
    __shared__ T Bs[TILE_SIZE][TILE_SIZE];

    int row = blockIdx.y * TILE_SIZE + threadIdx.y;
    int col = blockIdx.x * TILE_SIZE + threadIdx.x;

    T sum = zero_value<T>();

    // Loop over tiles
    for (int t = 0; t < (in_features + TILE_SIZE - 1) / TILE_SIZE; ++t) {
        // Load tile from input matrix (A)
        int a_row = row;
        int a_col = t * TILE_SIZE + threadIdx.x;
        if (a_row < batch_size && a_col < in_features) {
            As[threadIdx.y][threadIdx.x] = input[a_row * in_features + a_col];
        } else {
            As[threadIdx.y][threadIdx.x] = zero_value<T>();
        }

        // Load tile from weight matrix (B) - note: weight is [out_features, in_features]
        int b_row = t * TILE_SIZE + threadIdx.y;
        int b_col = col;
        if (b_row < in_features && b_col < out_features) {
            Bs[threadIdx.y][threadIdx.x] = weight[b_col * in_features + b_row];  // Transposed access
        } else {
            Bs[threadIdx.y][threadIdx.x] = zero_value<T>();
        }

        __syncthreads();

        // Compute partial sum
        for (int k = 0; k < TILE_SIZE; ++k) {
            sum = add(sum, mul(As[threadIdx.y][k], Bs[k][threadIdx.y]));
        }

        __syncthreads();
    }

    // Write result with fused operations: (matmul + bias) * scaling_factor + (matmul + bias)
    if (row < batch_size && col < out_features) {
        T result = sum;
        if (bias != nullptr) {
            result = add(result, bias[col]);
        }
        // Original: x = matmul(x); original_x = x; x = x * scaling_factor; x = x + original_x
        // Simplified: result * scaling_factor + result = result * (scaling_factor + 1.0f)
        output[row * out_features + col] = scalar_mul(result, scaling_factor + 1.0f);
