        __syncthreads();

        // Compute partial sum
        for (int k = 0; k < TILE_SIZE; ++k) {
            sum = add(sum, mul(As[threadIdx.y][k], Bs[k][threadIdx.x]));
        }

    }

    // Write result with fused operations: (matmul + bias) * scaling_factor + (matmul + bias)
    if (row < batch_size && col < out_features) {
        T result = sum;
        if (bias != nullptr) {
            result = add(result, bias[col]);
