        // Original: x = matmul(x); original_x = x; x = x * scaling_factor; x = x + original_x
        // Simplified: result * scaling_factor + result = result * (scaling_factor + 1.0f)
        output[row * out_features + col] = scalar_mul(result, scaling_factor + 1.0f);
    }
